final class BiometricAuthManager {
    static let shared = BiometricAuthManager()
    private init() {}

    enum Availability {
        case available(type: LABiometryType)
        case unavailable(reason: String)
    }

    func availability() -> Availability {
        let context = LAContext()
        var error: NSError?
        let can = context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
        if can {
            let type = context.biometryType
            return .available(type: type)
        } else {
            let msg = (error?.localizedDescription).flatMap { $0.isEmpty ? nil : $0 } ?? "Biometric authentication is not available."
            return .unavailable(reason: msg)
        }
    }

    func biometricDisplayName(for type: LABiometryType) -> String {
        switch type {
        case .faceID: return "Face ID"
        case .touchID: return "Touch ID"
        default: return "Biometrics"
        }
    }

    func authenticateBiometrics(reason: String,
                                completion: @escaping (Result<Void, Error>) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Use Password"
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            completion(.failure(error ?? NSError(domain: "Biometric", code: -1, userInfo: [NSLocalizedDescriptionKey: "Biometrics not available."])))
            return
        }
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, evalError in
            if success {
                completion(.success(()))
            } else {
                completion(.failure(evalError ?? NSError(domain: "Biometric", code: -2, userInfo: [NSLocalizedDescriptionKey: "Authentication failed."])))
            }
        }
    }

    func authenticateWithSystemFallback(reason: String,
                                        completion: @escaping (Result<Void, Error>) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Cancel"
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthentication, error: &error) else {
            completion(.failure(error ?? NSError(domain: "Auth", code: -1, userInfo: [NSLocalizedDescriptionKey: "Authentication not available."])))
            return
        }
        context.evaluatePolicy(.deviceOwnerAuthentication, localizedReason: reason) { success, evalError in
            if success {
                completion(.success(()))
            } else {
                completion(.failure(evalError ?? NSError(domain: "Auth", code: -2, userInfo: [NSLocalizedDescriptionKey: "Authentication failed."])))
            }
        }
    }
}

// MARK: - App Launch Routing (SceneDelegate)

final class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    var window: UIWindow?

    func scene(_ scene: UIScene,
               willConnectTo session: UISceneSession,
               options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        let window = UIWindow(windowScene: windowScene)
        self.window = window

        if AuthManager.shared.isAuthenticated {
            window.rootViewController = MainViewController()
        } else {
            window.rootViewController = LoginViewController()
        }
        window.makeKeyAndVisible()
    }

    static func setRoot(_ vc: UIViewController, animated: Bool = true) {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let sceneDelegate = windowScene.delegate as? SceneDelegate,
              let window = sceneDelegate.window else { return }

        if !animated {
            window.rootViewController = vc
            return
        }

        let snapshot = window.snapshotView(afterScreenUpdates: true)
        window.rootViewController = vc
        if let snapshot {
            vc.view.addSubview(snapshot)
            UIView.animate(withDuration: 0.25, animations: {
                snapshot.alpha = 0
                snapshot.transform = CGAffineTransform(scaleX: 1.05, y: 1.05)
            }, completion: { _ in
                snapshot.removeFromSuperview()
            })
        }
    }
}

