// MARK: - Login

final class LoginViewController: UIViewController {

    private let titleLabel = UILabel()
    private let statusLabel = UILabel()
    private let biometricsButton = UIButton(type: .system)
    private let passwordField = UITextField()
    private let loginButton = UIButton(type: .system)

    private var biometryType: LABiometryType = .none

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground

        titleLabel.text = "Sign In"
        titleLabel.font = .systemFont(ofSize: 28, weight: .bold)
        titleLabel.textAlignment = .center

        statusLabel.text = ""
        statusLabel.textColor = .secondaryLabel
        statusLabel.numberOfLines = 0
        statusLabel.textAlignment = .center

        passwordField.placeholder = "Password"
        passwordField.isSecureTextEntry = true
        passwordField.borderStyle = .roundedRect
        passwordField.textContentType = .password
        passwordField.returnKeyType = .done
        passwordField.delegate = self

        loginButton.setTitle("Sign In with Password", for: .normal)
        loginButton.addTarget(self, action: #selector(didTapPasswordLogin), for: .touchUpInside)

        biometricsButton.addTarget(self, action: #selector(didTapBiometrics), for: .touchUpInside)

        let stack = UIStackView(arrangedSubviews: [
            titleLabel,
            statusLabel,
            biometricsButton,
            passwordField,
            loginButton
        ])
        stack.axis = .vertical
        stack.spacing = 14
        stack.translatesAutoresizingMaskIntoConstraints = false

        view.addSubview(stack)
        NSLayoutConstraint.activate([
            stack.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 24),
            stack.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -24),
            stack.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])

        refreshBiometricsUI()
    }

    override func viewDidAppear(_ animated: Bool) {
        super.viewDidAppear(animated)

        guard !AuthManager.shared.isAuthenticated else {
            SceneDelegate.setRoot(MainViewController(), animated: false)
            return
        }

        attemptBiometricLoginIfAvailable()
    }

    private func refreshBiometricsUI() {
        switch BiometricAuthManager.shared.availability() {
        case .available(let type):
            biometryType = type
            let name = BiometricAuthManager.shared.biometricDisplayName(for: type)
            biometricsButton.setTitle("Sign In with \(name)", for: .normal)
            biometricsButton.isEnabled = true
            biometricsButton.isHidden = false
        case .unavailable:
            biometryType = .none
            biometricsButton.setTitle("Biometrics Unavailable", for: .normal)
            biometricsButton.isEnabled = false
            biometricsButton.isHidden = true
        }
    }

    private func attemptBiometricLoginIfAvailable() {
        guard case .available(let type) = BiometricAuthManager.shared.availability() else { return }
        let name = BiometricAuthManager.shared.biometricDisplayName(for: type)
        let reason = "Use \(name) to sign in."

        BiometricAuthManager.shared.authenticateBiometrics(reason: reason) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success:
                    AuthManager.shared.setAuthenticated(true)
                    self?.statusLabel.text = ""
                    SceneDelegate.setRoot(MainViewController(), animated: true)
                case .failure(let error):
                    self?.handleBiometricFailure(error: error, type: type)
                }
            }
        }
    }

    private func handleBiometricFailure(error: Error, type: LABiometryType) {
        let laError = error as? LAError
        let name = BiometricAuthManager.shared.biometricDisplayName(for: type)

        switch laError?.code {
        case .userCancel, .appCancel, .systemCancel:
            statusLabel.text = "Authentication canceled. You can try again or use your password."
            return
        case .userFallback:
            statusLabel.text = "Enter your password to sign in."
            passwordField.becomeFirstResponder()
            return
        case .biometryLockout:
            statusLabel.text = "\(name) is temporarily locked. You can authenticate using device passcode, then continue."
            presentLockoutOptions(reason: "Authenticate to re-enable \(name) and sign in.")
            return
        default:
            statusLabel.text = "Couldn’t verify \(name). Try again or use your password."
            presentRetryOrPassword(name: name)
        }
    }

    private func presentRetryOrPassword(name: String) {
        let alert = UIAlertController(title: "\(name) Failed",
                                      message: "Try again or sign in with your password.",
                                      preferredStyle: .alert)

        alert.addAction(UIAlertAction(title: "Try Again", style: .default, handler: { [weak self] _ in
            self?.attemptBiometricLoginIfAvailable()
        }))

        alert.addAction(UIAlertAction(title: "Use Password", style: .default, handler: { [weak self] _ in
            self?.passwordField.becomeFirstResponder()
        }))

        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel, handler: nil))
        present(alert, animated: true)
    }

    private func presentLockoutOptions(reason: String) {
        let alert = UIAlertController(title: "Authentication Required",
                                      message: "To continue, authenticate with your device passcode.",
                                      preferredStyle: .alert)

        alert.addAction(UIAlertAction(title: "Use Passcode", style: .default, handler: { _ in
            BiometricAuthManager.shared.authenticateWithSystemFallback(reason: reason) { [weak self] result in
                DispatchQueue.main.async {
                    switch result {
                    case .success:
                        AuthManager.shared.setAuthenticated(true)
                        self?.statusLabel.text = ""
                        SceneDelegate.setRoot(MainViewController(), animated: true)
                    case .failure:
                        self?.statusLabel.text = "Authentication failed. Please use your password."
                        self?.passwordField.becomeFirstResponder()
                    }
                }
            }
        }))

        alert.addAction(UIAlertAction(title: "Use Password", style: .default, handler: { [weak self] _ in
            self?.passwordField.becomeFirstResponder()
        }))

        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel, handler: nil))
        present(alert, animated: true)
    }

    @objc private func didTapBiometrics() {
        attemptBiometricLoginIfAvailable()
    }

    @objc private func didTapPasswordLogin() {
        view.endEditing(true)

        let password = passwordField.text ?? ""
        guard !password.isEmpty else {
            statusLabel.text = "Enter your password."
            passwordField.becomeFirstResponder()
            return
        }

        if verifyPassword(password) {
            AuthManager.shared.setAuthenticated(true)
            statusLabel.text = ""
            SceneDelegate.setRoot(MainViewController(), animated: true)
        } else {
            statusLabel.text = "Incorrect password. Please try again."
            passwordField.becomeFirstResponder()
        }
    }

    private func verifyPassword(_ password: String) -> Bool {
        // Replace with real backend/local validation.
        return password == "password"
    }
}

extension LoginViewController: UITextFieldDelegate {
    func textFieldShouldReturn(_ textField: UITextField) -> Bool {
        didTapPasswordLogin()
        return true
    }
}

